        l.right_child_count = p_left_count + p_right_count + 1;

        let left_depth = l.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        let right_depth = l.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        l.depth = std::cmp::max(left_depth, right_depth);
    }

    l_rc
}

fn _bostree_rotate_left(tree: &mut BOSTree, p_rc: Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let r_rc = p_rc.borrow().right_child_node.as_ref().unwrap().clone();

    let p_parent = p_rc.borrow().parent_node.clone();
    if let Some(parent_weak) = &p_parent {
        let parent_rc = parent_weak.upgrade().unwrap();
        let mut parent = parent_rc.borrow_mut();
        let is_left = if let Some(left) = &parent.left_child_node {
            Rc::ptr_eq(left, &p_rc)
        } else {
            false
        };
        if is_left {
            parent.left_child_node = Some(r_rc.clone());
        } else {
            parent.right_child_node = Some(r_rc.clone());
        }
    } else {
        tree.root_node = Some(r_rc.clone());
    }

    r_rc.borrow_mut().parent_node = p_parent.clone();

    let r_left = r_rc.borrow().left_child_node.clone();
    let r_left_count = r_rc.borrow().left_child_count;

    {
        let mut p = p_rc.borrow_mut();
        p.right_child_node = r_left.clone();
        p.right_child_count = r_left_count;
        if let Some(rl) = &r_left {
            rl.borrow_mut().parent_node = Some(Rc::downgrade(&p_rc));
        }

        let left_depth = p.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        let right_depth = p.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        p.depth = std::cmp::max(left_depth, right_depth);
        p.parent_node = Some(Rc::downgrade(&r_rc));
    }

    {
        let mut r = r_rc.borrow_mut();
        r.left_child_node = Some(p_rc.clone());

        let p_left_count = p_rc.borrow().left_child_count;
        let p_right_count = p_rc.borrow().right_child_count;
        r.left_child_count = p_left_count + p_right_count + 1;

        let left_depth = r.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        let right_depth = r.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        r.depth = std::cmp::max(left_depth, right_depth);
    }

    r_rc
}

impl BOSTree {
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    pub fn bostree_node_count(&self) -> u32 {
        if let Some(root) = &self.root_node {
            let r = root.borrow();
            r.left_child_count + r.right_child_count + 1
        } else {
            0
        }
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let mut current_node = self.root_node.clone();
        let mut parent_node: Option<Rc<RefCell<BOSNode>>> = None;

        while let Some(node_rc) = current_node.clone() {
            parent_node = Some(node_rc.clone());
            let cmp = (self.cmp_function)(&key, &node_rc.borrow().key);
            if cmp < 0 {
                node_rc.borrow_mut().left_child_count += 1;
                current_node = node_rc.borrow().left_child_node.clone();
            } else {
                node_rc.borrow_mut().right_child_count += 1;
                current_node = node_rc.borrow().right_child_node.clone();
            }
        }

        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: parent_node.as_ref().map(|p| Rc::downgrade(p)),
            key,
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));

        if let Some(parent_rc) = parent_node {
            let cmp = (self.cmp_function)(&new_node.borrow().key, &parent_rc.borrow().key);
            if cmp < 0 {
                parent_rc.borrow_mut().left_child_node = Some(new_node.clone());
            } else {
                parent_rc.borrow_mut().right_child_node = Some(new_node.clone());
            }

            let has_left = parent_rc.borrow().left_child_node.is_some();
            let has_right = parent_rc.borrow().right_child_node.is_some();

            if has_left ^ has_right {
                parent_rc.borrow_mut().depth += 1;
                let mut p_node = parent_rc.clone();

                loop {
                    let parent_parent = p_node.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                    if let Some(pp) = parent_parent {
                        p_node = pp;

                        let left_depth = p_node.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                        let right_depth = p_node.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                        let max_depth = std::cmp::max(left_depth, right_depth);

                        if p_node.borrow().depth != max_depth {
                            p_node.borrow_mut().depth = max_depth;
                        } else {
                            break;
                        }

                        let left_depth_i32 = left_depth as i32;
                        let right_depth_i32 = right_depth as i32;

                        if left_depth_i32 - 2 == right_depth_i32 {
                            let left_child = p_node.borrow().left_child_node.as_ref().unwrap().clone();
                            if _bostree_balance(&Some(left_child.clone())) > 0 {
                                _bostree_rotate_left(self, left_child);
                            }
                            p_node = _bostree_rotate_right(self, p_node.clone());
                        } else if left_depth_i32 + 2 == right_depth_i32 {
                            let right_child = p_node.borrow().right_child_node.as_ref().unwrap().clone();
                            if _bostree_balance(&Some(right_child.clone())) < 0 {
                                _bostree_rotate_right(self, right_child);
                            }
                            p_node = _bostree_rotate_left(self, p_node.clone());
                        }
                    } else {
                        break;
                    }
                }
            }
        } else {
            self.root_node = Some(new_node.clone());
        }

        new_node
    }

    pub fn bostree_remove(&mut self, node_rc: &Rc<RefCell<BOSNode>>) {
        let mut bubble_up: Option<Rc<RefCell<BOSNode>>>;

        let has_left = node_rc.borrow().left_child_node.is_some();
        let has_right = node_rc.borrow().right_child_node.is_some();

        if has_left && has_right {
            let mut candidate = node_rc.borrow().right_child_node.clone().unwrap();
            while candidate.clone().borrow().left_child_node.is_some() {
                let next = candidate.borrow().left_child_node.clone().unwrap();
                candidate = next;
            }

            let mut bubble_start = candidate.borrow().parent_node.as_ref().unwrap().upgrade().unwrap();

            if !Rc::ptr_eq(&bubble_start, node_rc) {
                let cand_right = candidate.borrow().right_child_node.clone();
                bubble_start.borrow_mut().left_child_node = cand_right.clone();
                if let Some(cr) = cand_right {
                    cr.borrow_mut().parent_node = Some(Rc::downgrade(&bubble_start));
                }
            }

            let node_parent = node_rc.borrow().parent_node.clone();
            if let Some(parent_weak) = &node_parent {
                let parent = parent_weak.upgrade().unwrap();
                let is_left = if let Some(left) = &parent.borrow().left_child_node {
                    Rc::ptr_eq(left, node_rc)
                } else {
                    false
                };
                if is_left {
                    parent.borrow_mut().left_child_node = Some(candidate.clone());
                } else {
                    parent.borrow_mut().right_child_node = Some(candidate.clone());
                }
            } else {
                self.root_node = Some(candidate.clone());
            }
            candidate.borrow_mut().parent_node = node_parent.clone();

            let node_left = node_rc.borrow().left_child_node.clone();
            let node_left_count = node_rc.borrow().left_child_count;
            let node_right = node_rc.borrow().right_child_node.clone();
            let node_right_count = node_rc.borrow().right_child_count;

            candidate.borrow_mut().left_child_node = node_left.clone();
            candidate.borrow_mut().left_child_count = node_left_count;
            candidate.borrow_mut().right_child_node = node_right.clone();
            candidate.borrow_mut().right_child_count = node_right_count;

            if let Some(nl) = node_left {
                nl.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }
            if let Some(nr) = node_right {
                nr.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }

            if !Rc::ptr_eq(&bubble_start, node_rc) {
                while !Rc::ptr_eq(&bubble_start, &candidate) {
                    let left_depth = bubble_start.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                    let right_depth = bubble_start.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                    bubble_start.borrow_mut().depth = std::cmp::max(left_depth, right_depth);

                    let balance = _bostree_balance(&Some(bubble_start.clone()));
                    if balance > 1 {
                        let right_child = bubble_start.borrow().right_child_node.as_ref().unwrap().clone();
                        if _bostree_balance(&Some(right_child.clone())) < 0 {
                            _bostree_rotate_right(self, right_child);
                        }
                        bubble_start = _bostree_rotate_left(self, bubble_start.clone());
                    } else if balance < -1 {
                        let left_child = bubble_start.borrow().left_child_node.as_ref().unwrap().clone();
                        if _bostree_balance(&Some(left_child.clone())) > 0 {
                            _bostree_rotate_left(self, left_child);
                        }
                        bubble_start = _bostree_rotate_right(self, bubble_start.clone());
                    }

                    let next_parent = bubble_start.borrow().parent_node.as_ref().unwrap().upgrade().unwrap();
                    bubble_start = next_parent;
                }
            }

            let left_depth = candidate.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
            let right_depth = candidate.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
            candidate.borrow_mut().depth = std::cmp::max(left_depth, right_depth);

            bubble_up = candidate.borrow().parent_node.as_ref().and_then(|w| w.upgrade());

            if let Some(bu) = &bubble_up {
                let is_left = if let Some(left) = &bu.borrow().left_child_node {
                    Rc::ptr_eq(left, &candidate)
                } else {
                    false
                };
                if is_left {
                    bu.borrow_mut().left_child_count -= 1;
                } else {
                    bu.borrow_mut().right_child_count -= 1;
                }
            }
        } else {
            let node_parent = node_rc.borrow().parent_node.clone();
            if node_parent.is_none() {
                if let Some(left) = node_rc.borrow().left_child_node.clone() {
                    self.root_node = Some(left.clone());
                    left.borrow_mut().parent_node = None;
                } else if let Some(right) = node_rc.borrow().right_child_node.clone() {
                    self.root_node = Some(right.clone());
                    right.borrow_mut().parent_node = None;
                } else {
                    self.root_node = None;
                }
                bubble_up = None;
            } else {
                let parent = node_parent.as_ref().unwrap().upgrade().unwrap();
                let mut candidate = node_rc.borrow().left_child_node.clone();
                let mut candidate_count = node_rc.borrow().left_child_count;
                if node_rc.borrow().right_child_node.is_some() {
                    candidate = node_rc.borrow().right_child_node.clone();
                    candidate_count = node_rc.borrow().right_child_count;
                }

                let is_left = if let Some(left) = &parent.borrow().left_child_node {
                    Rc::ptr_eq(left, node_rc)
                } else {
                    false
                };

                if is_left {
                    parent.borrow_mut().left_child_node = candidate.clone();
                    parent.borrow_mut().left_child_count = candidate_count;
                } else {
                    parent.borrow_mut().right_child_node = candidate.clone();
                    parent.borrow_mut().right_child_count = candidate_count;
                }

                if let Some(cand) = &candidate {
                    cand.borrow_mut().parent_node = node_parent.clone();
                }

                bubble_up = Some(parent);
            }
        }

        let mut bubbling_finished = false;
        while let Some(mut current_bu) = bubble_up {
            if !bubbling_finished {
                let left_depth = current_bu.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                let right_depth = current_bu.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                let new_depth = std::cmp::max(left_depth, right_depth);
                let depth_changed = new_depth != current_bu.borrow().depth;
                current_bu.borrow_mut().depth = new_depth;

                let balance = _bostree_balance(&Some(current_bu.clone()));
                if balance < -1 {
                    let left_child = current_bu.borrow().left_child_node.as_ref().unwrap().clone();
                    if _bostree_balance(&Some(left_child.clone())) > 0 {
                        _bostree_rotate_left(self, left_child);
                    }
                    current_bu = _bostree_rotate_right(self, current_bu.clone());
                } else if balance > 1 {
                    let right_child = current_bu.borrow().right_child_node.as_ref().unwrap().clone();
                    if _bostree_balance(&Some(right_child.clone())) < 0 {
                        _bostree_rotate_right(self, right_child);
                    }
                    current_bu = _bostree_rotate_left(self, current_bu.clone());
                }

                if !depth_changed && balance >= -1 && balance <= 1 {
                    bubbling_finished = true;
                }
            }

            let parent_opt = current_bu.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            if let Some(parent) = &parent_opt {
                let is_left = if let Some(left) = &parent.borrow().left_child_node {
                    Rc::ptr_eq(left, &current_bu)
                } else {
                    false
                };
                if is_left {
                    parent.borrow_mut().left_child_count -= 1;
                } else {
                    parent.borrow_mut().right_child_count -= 1;
                }
            }
            bubble_up = parent_opt;
        }

        node_rc.borrow_mut().weak_ref_node_valid = 0;
        self.bostree_node_weak_unref(node_rc);
    }

    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        node.borrow_mut().weak_ref_count -= 1;
        if node.borrow().weak_ref_count == 0 {
            if let Some(free_fn) = self.free_function {
                free_fn(node);
            }
            node.borrow_mut().left_child_node = None;
            node.borrow_mut().right_child_node = None;
            node.borrow_mut().parent_node = None;
            None
        } else if node.borrow().weak_ref_node_valid != 0 {
            Some(node.clone())
        } else {
            None
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        while let Some(n) = node.clone() {
            let cmp = (self.cmp_function)(key, &n.borrow().key);
            if cmp == 0 {
                return Some(n);
            } else if cmp < 0 {
                node = n.borrow().left_child_node.clone();
            } else {
                node = n.borrow().right_child_node.clone();
            }
        }
        None
    }

    pub fn bostree_select(&self, mut index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        while let Some(n) = node.clone() {
            let left_count = n.borrow().left_child_count;
            if left_count <= index {
                index -= left_count;
                if index == 0 {
                    return Some(n);
                }
                index -= 1;
                node = n.borrow().right_child_node.clone();
            } else {
                node = n.borrow().left_child_node.clone();
            }
        }
        None
    }

    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        if let Some(root) = &self.root_node {
            println!("digraph {{\n  ordering = out;");
            Self::_bostree_print_helper(root);
            println!("}}");
        }
    }

    #[cfg(debug_assertions)]
    fn _bostree_print_helper(node: &Rc<RefCell<BOSNode>>) {
        let n = node.borrow();
        println!("  \"{}\" [label=\"\\N ({},{},{}){}\"];", n.key, n.left_child_count, n.right_child_count, n.depth, if n.weak_ref_node_valid == 0 { " INVALID" } else { "" });
        if let Some(parent_weak) = &n.parent_node {
            if let Some(parent) = parent_weak.upgrade() {
                println!("  \"{}\" -> \"{}\" [color=green];", n.key, parent.borrow().key);
            }
        }
        if let Some(left) = &n.left_child_node {
            println!("  \"{}\" -> \"{}\"", n.key, left.borrow().key);
            Self::_bostree_print_helper(left);
        }
        if let Some(right) = &n.right_child_node {
            println!("  \"{}\" -> \"{}\"", n.key, right.borrow().key);
            Self::_bostree_print_helper(right);
        }
    }
}

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    assert!(node.borrow().weak_ref_count < 127);
    assert!(node.borrow().weak_ref_count > 0);
    node.borrow_mut().weak_ref_count += 1;
    node.clone()
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(right) = node.borrow().right_child_node.clone() {
        let mut n = right;
        while let Some(left) = n.clone().borrow().left_child_node.clone() {
            n = left;
        }
        Some(n)
    } else {
        let mut current = node.clone();
        while let Some(parent) = current.clone().borrow().parent_node.as_ref().and_then(|w| w.upgrade()) {
            let is_right = if let Some(right) = &parent.borrow().right_child_node {
                Rc::ptr_eq(right, &current)
            } else {
                false
            };
            if is_right {
                current = parent;
            } else {
                return Some(parent);
            }
        }
        None
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(left) = node.borrow().left_child_node.clone() {
        let mut n = left;
        while let Some(right) = n.clone().borrow().right_child_node.clone() {
            n = right;
        }
        Some(n)
    } else {
        let mut current = node.clone();
        while let Some(parent) = current.clone().borrow().parent_node.as_ref().and_then(|w| w.upgrade()) {
            let is_left = if let Some(left) = &parent.borrow().left_child_node {
                Rc::ptr_eq(left, &current)
            } else {
                false
            };
            if is_left {
                current = parent;
            } else {
                return Some(parent);
            }
        }
        None
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = node.clone();

    while let Some(parent) = current.clone().borrow().parent_node.as_ref().and_then(|w| w.upgrade()) {
        let is_right = if let Some(right) = &parent.borrow().right_child_node {
            Rc::ptr_eq(right, &current)
        } else {
            false
        };
        if is_right {
            counter += 1 + parent.borrow().left_child_count;
        }
        current = parent;
    }
    counter
}
