        l_mut.right_child_node = Some(p.clone());
        let p_left_count = p.borrow().left_child_count;
        let p_right_count = p.borrow().right_child_count;
        l_mut.right_child_count = p_left_count + p_right_count + 1;
        let ld = l_mut.left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
        let rd = l_mut.right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
        l_mut.depth = _imax(ld, rd);
    }
    l
}

fn _bostree_rotate_left(tree: &mut BOSTree, p: Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let r = p.borrow().right_child_node.as_ref().unwrap().clone();

    let p_parent = p.borrow().parent_node.clone();
    if let Some(parent_weak) = &p_parent {
        let parent_rc = parent_weak.upgrade().unwrap();
        let mut parent = parent_rc.borrow_mut();
        let is_left = parent.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &p));
        if is_left {
            parent.left_child_node = Some(r.clone());
        } else {
            parent.right_child_node = Some(r.clone());
        }
    } else {
        tree.root_node = Some(r.clone());
    }

    r.borrow_mut().parent_node = p_parent;

    let r_left = r.borrow().left_child_node.clone();
    let r_left_count = r.borrow().left_child_count;

    {
        let mut p_mut = p.borrow_mut();
        p_mut.right_child_node = r_left.clone();
        p_mut.right_child_count = r_left_count;
        if let Some(rl) = &r_left {
            rl.borrow_mut().parent_node = Some(Rc::downgrade(&p));
        }
        let ld = p_mut.left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
        let rd = p_mut.right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
        p_mut.depth = _imax(ld, rd);
        p_mut.parent_node = Some(Rc::downgrade(&r));
    }

    {
        let mut r_mut = r.borrow_mut();
        r_mut.left_child_node = Some(p.clone());
        let p_left_count = p.borrow().left_child_count;
        let p_right_count = p.borrow().right_child_count;
        r_mut.left_child_count = p_left_count + p_right_count + 1;
        let ld = r_mut.left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
        let rd = r_mut.right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
        r_mut.depth = _imax(ld, rd);
    }
    r
}

impl BOSTree {
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        Self {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    pub fn bostree_node_count(&self) -> u32 {
        if let Some(r) = &self.root_node {
            let rb = r.borrow();
            rb.left_child_count + rb.right_child_count + 1
        } else {
            0
        }
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let mut node = self.root_node.clone();
        let mut parent_node: Option<Rc<RefCell<BOSNode>>> = None;

        while let Some(n) = node.clone() {
            parent_node = Some(n.clone());
            let cmp = (self.cmp_function)(&key, &n.borrow().key);
            if cmp < 0 {
                n.borrow_mut().left_child_count += 1;
                node = n.borrow().left_child_node.clone();
            } else {
                n.borrow_mut().right_child_count += 1;
                node = n.borrow().right_child_node.clone();
            }
        }

        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: parent_node.as_ref().map(Rc::downgrade),
            key,
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));

        if let Some(parent) = parent_node {
            let cmp = (self.cmp_function)(&new_node.borrow().key, &parent.borrow().key);
            if cmp < 0 {
                parent.borrow_mut().left_child_node = Some(new_node.clone());
            } else {
                parent.borrow_mut().right_child_node = Some(new_node.clone());
            }

            let has_left = parent.borrow().left_child_node.is_some();
            let has_right = parent.borrow().right_child_node.is_some();

            if has_left ^ has_right {
                parent.borrow_mut().depth += 1;
                let mut curr = parent;

                while let Some(p_parent_weak) = curr.clone().borrow().parent_node.clone() {
                    let p_parent = p_parent_weak.upgrade().unwrap();
                    curr = p_parent;

                    let ld = curr.borrow().left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
                    let rd = curr.borrow().right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
                    let max_d = _imax(ld, rd);

                    if curr.borrow().depth != max_d {
                        curr.borrow_mut().depth = max_d;
                    } else {
                        break;
                    }

                    let ld_i32 = ld as i32;
                    let rd_i32 = rd as i32;

                    if ld_i32 - 2 == rd_i32 {
                        let left = curr.borrow().left_child_node.as_ref().unwrap().clone();
                        if _bostree_balance(&left) > 0 {
                            _bostree_rotate_left(self, left);
                        }
                        curr = _bostree_rotate_right(self, curr.clone());
                    } else if ld_i32 + 2 == rd_i32 {
                        let right = curr.borrow().right_child_node.as_ref().unwrap().clone();
                        if _bostree_balance(&right) < 0 {
                            _bostree_rotate_right(self, right);
                        }
                        curr = _bostree_rotate_left(self, curr.clone());
                    }
                }
            }
        } else {
            self.root_node = Some(new_node.clone());
        }

        new_node
    }

    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let mut bubble_up: Option<Rc<RefCell<BOSNode>>> = None;

        let has_left = node.borrow().left_child_node.is_some();
        let has_right = node.borrow().right_child_node.is_some();

        if has_left && has_right {
            let mut candidate = node.borrow().right_child_node.as_ref().unwrap().clone();
            while let Some(left) = candidate.clone().borrow().left_child_node.clone() {
                candidate = left;
            }

            let mut bubble_start = candidate.borrow().parent_node.as_ref().unwrap().upgrade().unwrap();

            if !Rc::ptr_eq(&bubble_start, node) {
                let c_right = candidate.borrow().right_child_node.clone();
                bubble_start.borrow_mut().left_child_node = c_right.clone();
                if let Some(cr) = c_right {
                    cr.borrow_mut().parent_node = Some(Rc::downgrade(&bubble_start));
                }
            }

            let n_parent = node.borrow().parent_node.clone();
            if let Some(parent_weak) = &n_parent {
                let parent = parent_weak.upgrade().unwrap();
                let is_left = parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node));
                if is_left {
                    parent.borrow_mut().left_child_node = Some(candidate.clone());
                } else {
                    parent.borrow_mut().right_child_node = Some(candidate.clone());
                }
            } else {
                self.root_node = Some(candidate.clone());
            }
            candidate.borrow_mut().parent_node = n_parent;

            let n_left = node.borrow().left_child_node.clone();
            let n_left_count = node.borrow().left_child_count;
            let n_right = node.borrow().right_child_node.clone();
            let n_right_count = node.borrow().right_child_count;

            candidate.borrow_mut().left_child_node = n_left.clone();
            candidate.borrow_mut().left_child_count = n_left_count;
            candidate.borrow_mut().right_child_node = n_right.clone();
            candidate.borrow_mut().right_child_count = n_right_count;

            if let Some(nl) = n_left {
                nl.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }
            if let Some(nr) = n_right {
                nr.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }

            if !Rc::ptr_eq(&bubble_start, node) {
                while !Rc::ptr_eq(&bubble_start, &candidate) {
                    let ld = bubble_start.borrow().left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
                    let rd = bubble_start.borrow().right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
                    bubble_start.borrow_mut().depth = _imax(ld, rd);

                    let balance = _bostree_balance(&bubble_start);
                    if balance > 1 {
                        let right = bubble_start.borrow().right_child_node.as_ref().unwrap().clone();
                        if _bostree_balance(&right) < 0 {
                            _bostree_rotate_right(self, right);
                        }
                        bubble_start = _bostree_rotate_left(self, bubble_start.clone());
                    } else if balance < -1 {
                        let left = bubble_start.borrow().left_child_node.as_ref().unwrap().clone();
                        if _bostree_balance(&left) > 0 {
                            _bostree_rotate_left(self, left);
                        }
                        bubble_start = _bostree_rotate_right(self, bubble_start.clone());
                    }
                    let next = bubble_start.borrow().parent_node.as_ref().unwrap().upgrade().unwrap();
                    bubble_start = next;
                }
            }

            let ld = candidate.borrow().left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
            let rd = candidate.borrow().right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
            candidate.borrow_mut().depth = _imax(ld, rd);

            bubble_up = candidate.borrow().parent_node.as_ref().map(|w| w.upgrade().unwrap());

            if let Some(bu) = &bubble_up {
                let is_left = bu.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate));
                if is_left {
                    bu.borrow_mut().left_child_count -= 1;
                } else {
                    bu.borrow_mut().right_child_count -= 1;
                }
            }
        } else {
            let n_parent = node.borrow().parent_node.clone();
            if n_parent.is_none() {
                if let Some(left) = node.borrow().left_child_node.clone() {
                    self.root_node = Some(left.clone());
                    left.borrow_mut().parent_node = None;
                } else if let Some(right) = node.borrow().right_child_node.clone() {
                    self.root_node = Some(right.clone());
                    right.borrow_mut().parent_node = None;
                } else {
                    self.root_node = None;
                }
                bubble_up = None;
            } else {
                let parent = n_parent.as_ref().unwrap().upgrade().unwrap();
                let mut candidate = node.borrow().left_child_node.clone();
                let mut candidate_count = node.borrow().left_child_count;
                if node.borrow().right_child_node.is_some() {
                    candidate = node.borrow().right_child_node.clone();
                    candidate_count = node.borrow().right_child_count;
                }

                let is_left = parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node));
                if is_left {
                    parent.borrow_mut().left_child_node = candidate.clone();
                    parent.borrow_mut().left_child_count = candidate_count;
                } else {
                    parent.borrow_mut().right_child_node = candidate.clone();
                    parent.borrow_mut().right_child_count = candidate_count;
                }

                if let Some(cand) = &candidate {
                    cand.borrow_mut().parent_node = n_parent.clone();
                }

                bubble_up = Some(parent);
            }
        }

        let mut bubbling_finished = false;
        while let Some(mut bu) = bubble_up.clone() {
            if !bubbling_finished {
                let ld = bu.borrow().left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
                let rd = bu.borrow().right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
                let new_depth = _imax(ld, rd);
                let depth_changed = new_depth != bu.borrow().depth;
                bu.borrow_mut().depth = new_depth;

                let balance = _bostree_balance(&bu);
                if balance < -1 {
                    let left = bu.borrow().left_child_node.as_ref().unwrap().clone();
                    if _bostree_balance(&left) > 0 {
                        _bostree_rotate_left(self, left);
                    }
                    bu = _bostree_rotate_right(self, bu.clone());
                } else if balance > 1 {
                    let right = bu.borrow().right_child_node.as_ref().unwrap().clone();
                    if _bostree_balance(&right) < 0 {
                        _bostree_rotate_right(self, right);
                    }
                    bu = _bostree_rotate_left(self, bu.clone());
                }

                if !depth_changed && balance >= -1 && balance <= 1 {
                    bubbling_finished = true;
                }
            }

            let next_parent = bu.borrow().parent_node.as_ref().map(|w| w.upgrade().unwrap());
            if let Some(parent) = &next_parent {
                let is_left = parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &bu));
                if is_left {
                    parent.borrow_mut().left_child_count -= 1;
                } else {
                    parent.borrow_mut().right_child_count -= 1;
                }
            }
            bubble_up = next_parent;
        }

        node.borrow_mut().weak_ref_node_valid = 0;
        self.bostree_node_weak_unref(node);
    }

    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        node.borrow_mut().weak_ref_count -= 1;
        if node.borrow().weak_ref_count == 0 {
            if let Some(free_fn) = self.free_function {
                free_fn(node);
            }
            None
        } else if node.borrow().weak_ref_node_valid != 0 {
            Some(node.clone())
        } else {
            None
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        while let Some(n) = node.clone() {
            let cmp = (self.cmp_function)(key, &n.borrow().key);
            if cmp == 0 {
                return Some(n);
            } else if cmp < 0 {
                node = n.borrow().left_child_node.clone();
            } else {
                node = n.borrow().right_child_node.clone();
            }
        }
        None
    }

    pub fn bostree_select(&self, mut index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        while let Some(n) = node.clone() {
            let lc = n.borrow().left_child_count;
            if lc <= index {
                index -= lc;
                if index == 0 {
                    return Some(n);
                }
                index -= 1;
                node = n.borrow().right_child_node.clone();
            } else {
                node = n.borrow().left_child_node.clone();
            }
        }
        None
    }

    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {}
}

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    node.borrow_mut().weak_ref_count += 1;
    node.clone()
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(right) = node.borrow().right_child_node.clone() {
        let mut n = right;
        while let Some(left) = n.clone().borrow().left_child_node.clone() {
            n = left;
        }
        Some(n)
    } else {
        let mut curr = node.clone();
        while let Some(parent) = curr.clone().borrow().parent_node.as_ref().map(|w| w.upgrade().unwrap()) {
            let is_right = parent.borrow().right_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &curr));
            if is_right {
                curr = parent;
            } else {
                return Some(parent);
            }
        }
        None
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(left) = node.borrow().left_child_node.clone() {
        let mut n = left;
        while let Some(right) = n.clone().borrow().right_child_node.clone() {
            n = right;
        }
        Some(n)
    } else {
        let mut curr = node.clone();
        while let Some(parent) = curr.clone().borrow().parent_node.as_ref().map(|w| w.upgrade().unwrap()) {
            let is_left = parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &curr));
            if is_left {
                curr = parent;
            } else {
                return Some(parent);
            }
        }
        None
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut curr = node.clone();
    while let Some(parent) = curr.clone().borrow().parent_node.as_ref().map(|w| w.upgrade().unwrap()) {
        let is_right = parent.borrow().right_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &curr));
        if is_right {
            counter += 1 + parent.borrow().left_child_count;
        }
        curr = parent;
    }
    counter
}
