}

#[derive(Debug)]
pub struct BOSNode {
    pub left_child_count: u32,
    pub right_child_count: u32,
    pub depth: u32,
    pub left_child_node: Option<Rc<RefCell<BOSNode>>>,
    pub right_child_node: Option<Rc<RefCell<BOSNode>>>,
    pub parent_node: Option<Weak<RefCell<BOSNode>>>,
    pub key: String,
    pub data: Option<String>,
    pub weak_ref_count: u8,
    pub weak_ref_node_valid: u8,
}

pub type BOSTreeCmpFunction = fn(&str, &str) -> i32;
pub type BOSTreeFreeFunction = fn(&Rc<RefCell<BOSNode>>);

fn _imax(i1: u32, i2: u32) -> u32 {
    if i1 > i2 { i1 } else { i2 }
}

fn _bostree_balance(node: &Rc<RefCell<BOSNode>>) -> i32 {
    let n = node.borrow();
    let left_depth = n.left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
    let right_depth = n.right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
    (right_depth as i32) - (left_depth as i32)
}

fn _bostree_rotate_right(tree: &mut BOSTree, p: Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let l = p.borrow().left_child_node.as_ref().unwrap().clone();

    let p_parent = p.borrow().parent_node.clone();
    if let Some(parent_weak) = &p_parent {
        let parent_rc = parent_weak.upgrade().unwrap();
        let mut parent = parent_rc.borrow_mut();
        let is_left = parent.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &p));
        if is_left {
            parent.left_child_node = Some(l.clone());
        } else {
            parent.right_child_node = Some(l.clone());
        }
    } else {
        tree.root_node = Some(l.clone());
    }

    l.borrow_mut().parent_node = p_parent;

    let l_right = l.borrow().right_child_node.clone();
    let l_right_count = l.borrow().right_child_count;

    {
        let mut p_mut = p.borrow_mut();
        p_mut.left_child_node = l_right.clone();
        p_mut.left_child_count = l_right_count;
        if let Some(lr) = &l_right {
            lr.borrow_mut().parent_node = Some(Rc::downgrade(&p));
        }
        let ld = p_mut.left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
        let rd = p_mut.right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
        p_mut.depth = _imax(ld, rd);
        p_mut.parent_node = Some(Rc::downgrade(&l));
    }

    {
        let mut l_mut = l.borrow_mut();
        l_mut.right_child_node = Some(p.clone());
        let p_left_count = p.borrow().left_child_count;
        let p_right_count = p.borrow().right_child_count;
        l_mut.right_child_count = p_left_count + p_right_count + 1;
        let ld = l_mut.left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
        let rd = l_mut.right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
        l_mut.depth = _imax(ld, rd);
    }
    l
}

fn _bostree_rotate_left(tree: &mut BOSTree, p: Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
